7	export class RoleGuardService  {
8	    constructor(public auth: AuthService, public router: Router, private itemService: itemService) { }
9	    async canActivate(route: ActivatedRouteSnapshot) {
10	        // this will be passed from the route config on the data property
11	        const roles: string | string[] = route.data.role; // Can be a string or an array of strings
12	
13	        if (!await this.auth.isAuthenticated()) {
14	            this.router.navigate(['/login']);
15	            return false;
16	        }
17	
18	        const token = localStorage.getItem('token');
19	        const tokenPayload = this.decodeToken(token);
20	        if (!tokenPayload) {
21	            this.router.navigate(['/login']);
22	            return false;
23	        }
24	
25	        const userRole = tokenPayload.role;
26	
27	        // Check if user role matches any of the allowed roles
28	        if (Array.isArray(roles) ? roles.includes(userRole) : roles === userRole) {
29	            return true;
30	        } else {
31	            this.router.navigate(['pages/error-401']);
32	            return false;
33	        }
34	    }
35	    async isAuth(role: any) {
36	        const token = localStorage.getItem('token');
37	        const tokenPayload = this.decodeToken(token);
38	        if (!tokenPayload) {
39	            this.router.navigate(['/login']);
40	            return false;
41	        }
42	
43	        if (await this.auth.isAuthenticated()) {
44	            if (tokenPayload.role != role) {
45	                return false;
46	            } else {
47	                return true;
48	            }
49	        } else {
50	            this.router.navigate(['/login']);
51	        }
52	    }
53	    getRole(){
54	        const token = localStorage.getItem('token');
55	        const tokenPayload = this.decodeToken(token);
56	        return tokenPayload?.role || '';
57	    }
58	    getUserId(){
59	        const token = localStorage.getItem('token');
60	        const tokenPayload = this.decodeToken(token);
61	        return tokenPayload?.user_id;
62	    }
63	
64	    private decodeToken(token: string | null): any {
65	        if (!token) return null;
66	        try {
67	            return decode(token);
68	        } catch {
69	            return null;
70	        }
71	    }
72	}
